export const UpdateTodo = (props) => {
    const { completeTodos, onClickUpdate } = props;

    return (
        <div>
            <ul>
            {completeTodos.map((todo, index) => (
            <li key={todo}>
                <button onClick={() => onClickUpdate(index)}></button>
            </li>
                )
            )}
            </ul>
        </div>
    )
}
